## DBsubject()
## DBchapter()
## DBsection()
## Level()
## KEYWORDS()
## TitleText1()
## EditionText1()
## AuthorText1()
## Section1(not reported)
## Problem1(1.5.8.9)
## Author()
## Institution()
## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PGlateximage.pl",
  "PCCmacros.pl",
  "PGchoicemacros.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "Pd.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
do {
  ($x,$y) = (-5..5)[NchooseK(11,2)];
  @h = (-9..$x-1,$x+1..9)[NchooseK(18,2)];
  @k = (-9..$y-1,$y+1..9)[NchooseK(18,2)];
  Context("Fraction");
  Context()->noreduce('(-x)+y', '(-x)-y');
  @m = map{Fraction(($y - $k[$_])/($x - $h[$_]))} (0,1);
} until ($m[0] != 1 && $m[1] != 1 && abs(atan2($m[0],1) - atan2($m[1],1)) > 0.2);
@f = map{Formula("$m[$_] (x - $h[$_]) + $k[$_]")->reduce} (0,1);
@high = map{(7 - $k[$_])/$m[$_] + $h[$_]} (0,1);
@low = map{(-7 - $k[$_])/$m[$_] + $h[$_]} (0,1);
@start = map{(num_sort(-7,7,$high[$_],$low[$_]))[1]} (0,1);
@stop = map{(num_sort(-7,7,$high[$_],$low[$_]))[2]} (0,1);
Context("Point");
Context()->strings->remove("NONE");
Context()->strings->add(
  "no solutions" => {},
);
for (
  "no solution",
  "none",
  "there are no solutions",
  "the solution set is empty",
  "solution set is empty",
  "empty set",
  "∅",
  "{}",
  "{ }",
  "{  }",
  "{   }"
) {
  Context()->strings->add($_ => {alias => "no solutions"});
}
$solution = Point($x,$y)->cmp(
  mathQuillOpts => 'disabled'
);

$image_1 = createLaTeXImage();
$image_1->addToPreamble(latexImagePreamble());
$image_1->BEGIN_LATEX_IMAGE
\begin{tikzpicture}
  \begin{axis}[
      width=0.33\orccaprintwidth
    ]
    \addplot[firstcurve,domain=$start[0]:$stop[0]]{$f[0]};
    \addplot[secondcurve,domain=$start[1]:$stop[1]]{$f[1]};
  \end{axis}
\end{tikzpicture}

END_LATEX_IMAGE

############################################################
# Body
############################################################

BEGIN_PGML
The graph of two lines represents a system of two linear equations. Use the graph to identify the solution to the system.

>> [@image(insertGraph($image_1), width=>600, alt=>qq"a coordinate plot of two lines that cross at ($x, $y)")@]*  <<

[@KeyboardInstructions('Enter the solution here. If there are no solutions, enter [|no solutions|]*.')@]**

[_]{$solution}{16}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
